import gspread
import os

# Check for credentials in various locations
cred_paths = [
    os.path.expanduser("~/.config/gspread/credentials.json"),
    os.path.expanduser("~/.config/gspread/service_account.json"),
    "/tmp/credentials.json",
    "/tmp/service_account.json",
]

for p in cred_paths:
    if os.path.exists(p):
        print(f"Found: {p}")

# Check env vars
for key in ["GSPREAD_CREDENTIALS", "GOOGLE_APPLICATION_CREDENTIALS", "GOOGLE_SHEETS_API_KEY", "GSPREAD_API_KEY"]:
    val = os.environ.get(key)
    if val:
        print(f"ENV {key}: {val[:50]}...")

# Try to use default credentials
try:
    gc = gspread.service_account()
    print("service_account() worked!")
except Exception as e:
    print(f"service_account() failed: {e}")

try:
    gc = gspread.api_key()
    print("api_key() worked!")
except Exception as e:
    print(f"api_key() failed: {e}")

EOF
